func (s *Server) generateSecureToken() string {
	b := make([]byte, 32)
	rand.Read(b)
	return base64.URLEncoding.EncodeToString(b)
}

func (s *Server) authenticateUser(r *http.Request) (*User, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, fmt.Errorf("missing authorization header")
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || parts[0] != "Bearer" {
		return nil, fmt.Errorf("invalid authorization format")
	}

	token := parts[1]

	s.mu.RLock()
	user, exists := s.usersByToken[token]
	s.mu.RUnlock()

	if !exists {
		return nil, fmt.Errorf("invalid token")
	}

	if time.Now().Before(user.BannedUntil) {
		return nil, fmt.Errorf("user is banned")
	}

	return user, nil
}

func (s *Server) validateAdminToken(token string) (Role, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	role, exists := s.adminTokens[token]
	return role, exists
}

func (s *Server) handleRegister(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req struct {
		Username   string `json:"username"`
		AdminToken string `json:"admin_token,omitempty"`
	}

	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	if req.Username == "" || len(req.Username) < 3 || len(req.Username) > 20 {
		http.Error(w, "Invalid username", http.StatusBadRequest)
		return
	}

	role := RoleUser
	if req.AdminToken != "" {
		if validatedRole, valid := s.validateAdminToken(req.AdminToken); valid {
			role = validatedRole
		}
	}

	userID := s.generateSecureToken()
	sessionToken := s.generateSecureToken()

	user := &User{
		ID:           userID,
		Username:     req.Username,
		Role:         role,
		SessionToken: sessionToken,
	}

	s.mu.Lock()
	s.users[userID] = user
	s.usersByToken[sessionToken] = user
	s.mu.Unlock()

	response := map[string]interface{}{
		"user_id": userID,
		"token":   sessionToken,
		"role":    role,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(response)
}

func (s *Server) handleWebSocket(w http.ResponseWriter, r *http.Request) {
	user, err := s.authenticateUser(r)
	if err != nil {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	conn, err := s.upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Printf("WebSocket upgrade error: %v", err)
		return
	}

	user.mu.Lock()
	user.conn = conn
	user.mu.Unlock()

	s.broadcastMessage(Message{
		Type:      "user_joined",
		Content:   fmt.Sprintf("%s joined the server", user.Username),
		Timestamp: time.Now(),
	})

	defer func() {
		user.mu.Lock()
		user.conn = nil
		user.mu.Unlock()

		s.broadcastMessage(Message{
			Type:      "user_left",
			Content:   fmt.Sprintf("%s left the server", user.Username),
			Timestamp: time.Now(),
		})
		conn.Close()
	}()

	for {
		var msg Message
		err := conn.ReadJSON(&msg)
		if err != nil {
			if websocket.IsUnexpectedCloseError(err, websocket.CloseGoingAway, websocket.CloseAbnormalClosure) {
				log.Printf("WebSocket error: %v", err)
			}
			break
		}

		if time.Now().Before(user.BannedUntil) {
			s.sendToUser(user, Message{
				Type:      "error",
				Content:   "You are banned",
				Timestamp: time.Now(),
			})
			break
		}

		msg.From = user.Username
		msg.Timestamp = time.Now()

		if strings.HasPrefix(msg.Content, "/") {
			s.handleCommand(user, msg.Content)
		} else {
			s.broadcastMessage(msg)
		}
	}
}

func (s *Server) handleCommand(user *User, content string) {
	parts := strings.Fields(content)
	if len(parts) == 0 {
		return
	}

	cmd := Command{
		Name:   strings.TrimPrefix(parts[0], "/"),
		Args:   parts[1:],
		Sender: user,
	}

	switch cmd.Name {
	case "kick":
		s.handleKick(cmd)
	case "ban":
		s.handleBan(cmd)
	case "unban":
		s.handleUnban(cmd)
	case "giveitems":
		s.handleGiveItems(cmd)
	case "help":
		s.handleHelp(cmd)
	default:
		s.sendToUser(user, Message{
			Type:      "error",
			Content:   "Unknown command",
			Timestamp: time.Now(),
		})
	}
}

func (s *Server) hasPermission(user *User, requiredRole Role) bool {
	roleLevel := map[Role]int{
		RoleUser:  0,
		RoleMod:   1,
		RoleAdmin: 2,
	}

	return roleLevel[user.Role] >= roleLevel[requiredRole]
}

func (s *Server) handleKick(cmd Command) {
	if !s.hasPermission(cmd.Sender, RoleMod) {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Insufficient permissions",
			Timestamp: time.Now(),
		})
		return
	}

	if len(cmd.Args) < 1 {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Usage: /kick <username>",
			Timestamp: time.Now(),
		})
		return
	}

	targetUsername := cmd.Args[0]
	var targetUser *User

	s.mu.RLock()
	for _, u := range s.users {
		if u.Username == targetUsername {
			targetUser = u
			break
		}
	}
	s.mu.RUnlock()

	if targetUser == nil {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "User not found",
			Timestamp: time.Now(),
		})
		return
	}

	if s.hasPermission(targetUser, cmd.Sender.Role) {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Cannot kick user with equal or higher role",
			Timestamp: time.Now(),
		})
		return
	}

	targetUser.mu.Lock()
	if targetUser.conn != nil {
		targetUser.conn.Close()
	}
	targetUser.mu.Unlock()

	s.broadcastMessage(Message{
		Type:      "system",
		Content:   fmt.Sprintf("%s was kicked by %s", targetUsername, cmd.Sender.Username),
		Timestamp: time.Now(),
	})
}

func (s *Server) handleBan(cmd Command) {
	if !s.hasPermission(cmd.Sender, RoleAdmin) {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Insufficient permissions",
			Timestamp: time.Now(),
		})
		return
	}

	if len(cmd.Args) < 1 {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Usage: /ban <username> [duration_minutes]",
			Timestamp: time.Now(),
		})
		return
	}

	targetUsername := cmd.Args[0]
	duration := 60 * time.Minute

	if len(cmd.Args) > 1 {
		var minutes int
		fmt.Sscanf(cmd.Args[1], "%d", &minutes)
		if minutes > 0 {
			duration = time.Duration(minutes) * time.Minute
		}
	}

	var targetUser *User

	s.mu.RLock()
	for _, u := range s.users {
		if u.Username == targetUsername {
			targetUser = u
			break
		}
	}
	s.mu.RUnlock()

	if targetUser == nil {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "User not found",
			Timestamp: time.Now(),
		})
		return
	}

	if s.hasPermission(targetUser, RoleAdmin) {
		s.sendToUser(cmd.Sender, Message{
			Type:      "error",
			Content:   "Cannot ban admin users",
			Timestamp: time.Now(),
		})
		return
	}

	banUntil := time.Now().Add(duration)
	targetUser.BannedUntil = banUntil

	s.mu.Lock()
	s.bannedUsers[targetUser.ID] = banUntil
	s.mu.Unlock()

	targetUser.mu.Lock()
	if targetUser.conn != nil {
		targetUser.conn.Close()
	}
	targetUser.mu.Unlock()

	s.broadcastMessage(Message{
		Type:      "system",
		Content:   fmt.Sprintf("%s was banned by %s for %v", targetUsername, cmd.Sender.Username, duration),
		Timestamp: time.Now(),
	})
}

