func (s *Server) handleHelp(cmd Command) {
	helpText := "Available commands:\n"

	if s.hasPermission(cmd.Sender, RoleMod) {
		helpText += "/kick <username> - Kick a user\n"
	}

	if s.hasPermission(cmd.Sender, RoleAdmin) {
		helpText += "/ban <username> [minutes] - Ban a user\n"
		helpText += "/unban <username> - Unban a user\n"
		helpText += "/giveitems <username> <item> <quantity> - Give items to a user\n"
	}

	s.sendToUser(cmd.Sender, Message{
		Type:      "system",
		Content:   helpText,
		Timestamp: time.Now(),
	})
}

func (s *Server) sendToUser(user *User, msg Message) {
	user.mu.Lock()
	defer user.mu.Unlock()

	if user.conn != nil {
		user.conn.WriteJSON(msg)
	}
}

func (s *Server) broadcastMessage(msg Message) {
	s.mu.RLock()
	users := make([]*User, 0, len(s.users))
	for _, u := range s.users {
		users = append(users, u)
	}
	s.mu.RUnlock()

	for _, user := range users {
		s.sendToUser(user, msg)
	}
}

